Real64 CalcEmmelVertical(Real64 const WindAt10m,
                         Real64 const WindDir,     // Wind direction measured clockwise from geographic North
                         Real64 const SurfAzimuth) // or Facing, Direction the surface outward normal faces (degrees)
{

    // FUNCTION INFORMATION:
    //       AUTHOR         Brent Griffith
    //       DATE WRITTEN   Aug 2010

    // PURPOSE OF THIS FUNCTION:
    // calculate model equation for forced convection using Emmel correlation
    // for vertical walls

    // REFERENCES:
    // Emmel, M.G., M.O. Abadie, N. Mendes. 2007. New external convective
    //   heat transfer coefficient correlations for isolated low-rise buildings.
    //   Energy and Buildings 39 (2007) 335- 342

    Real64 Theta = CalcWindSurfaceTheta(WindDir, SurfAzimuth); // angle between wind and surface azimuth

    if (Theta <= 22.5) {
        return 5.15 * std::pow(WindAt10m, 0.81);
    }
    if (Theta <= 67.5) {
        return 3.34 * std::pow(WindAt10m, 0.84);
    }
    if (Theta <= 112.5) {
        return 4.78 * std::pow(WindAt10m, 0.71);
    }
    if (Theta <= 157.5) {
        return 4.05 * std::pow(WindAt10m, 0.77);
    }
    return 3.54 * std::pow(WindAt10m, 0.76);
}

Real64 CalcEmmelRoof(Real64 const WindAt10m,
                     Real64 const WindDir,                // Wind direction measured clockwise from geographic North
                     Real64 const LongAxisOutwardAzimuth) // or Facing, Direction the surface outward normal faces (degrees)
{

    // FUNCTION INFORMATION:
    //       AUTHOR         Brent Griffith
    //       DATE WRITTEN   Aug 2010

    // PURPOSE OF THIS FUNCTION:
    // calculate model equation for forced convection using Emmel correlation
    // for horizontal roofs

    // REFERENCES:
    // Emmel, M.G., M.O. Abadie, N. Mendes. 2007. New external convective
    //   heat transfer coefficient correlations for isolated low-rise buildings.
    //    Energy and Buildings 39 (2007) 335- 342

    Real64 Theta = CalcWindSurfaceTheta(WindDir, LongAxisOutwardAzimuth); // angle between wind and surface azimuth

    if (Theta <= 22.5) {
        return 5.11 * std::pow(WindAt10m, 0.78);
    }
    if (Theta <= 67.5) {
        return 4.60 * std::pow(WindAt10m, 0.79);
    }
    if (Theta <= 112.5) {
        return 3.67 * std::pow(WindAt10m, 0.85);
    }
    if (Theta <= 157.5) {
        return 4.60 * std::pow(WindAt10m, 0.79);
    }
    return 5.11 * std::pow(WindAt10m, 0.78);
}

Real64 CalcPipeTransBeam(Real64 const R,    // Reflectance of surface, constant (can be made R = f(theta) later)
                             Real64 const A,    // Aspect ratio, L / d
                             Real64 const Theta // Angle of entry in radians
    )
    {

        // SUBROUTINE INFORMATION:
        //       AUTHOR         Peter Graham Ellis
        //       DATE WRITTEN   May 2003
        //       MODIFIED       na
        //       RE-ENGINEERED  na

        // PURPOSE OF THIS SUBROUTINE:
        // Calculates the numerical integral for the transmittance of a reflective cylinder with
        // incident collimated beam radiation as described in Swift and Smith.

        // METHODOLOGY EMPLOYED:
        // Since this integral can be slow, a table of values is calculated and stored during
        // initialization of the TDD.  Intermediate values are calculated by interpolation.
        // Transmittance of sky and ground diffuse radiation is done by other functions.

        // REFERENCES:
        // Swift, P. D., and Smith, G. B.  "Cylindrical Mirror Light Pipes",
        //   Solar Energy Materials and Solar Cells 36 (1995), pp. 159-168.

        // OTHER NOTES:
        // The execution time of this function can be reduced by adjusting parameters N and xTol below.
        // However, there is some penalty in accuracy for N < 100,000 and xTol > 150.

        // USE STATEMENTS: na

        // Return value
        Real64 CalcPipeTransBeam;

        // Locals
        // FUNCTION ARGUMENT DEFINITIONS:

        // FUNCTION PARAMETER DEFINITIONS:
        Real64 constexpr N(100000.0); // Number of integration points
        Real64 constexpr xTol(150.0); // Tolerance factor to skip iterations where dT is approximately 0
        // Must be >= 1.0, increase this number to decrease the execution time
        Real64 const myLocalTiny(TINY(1.0));

        // FUNCTION LOCAL VARIABLE DECLARATIONS:
        Real64 i; // Integration interval between points
        Real64 s; // Entry point
        Real64 dT;
        Real64 T; // Beam transmittance for collimated solar real
        Real64 x; // Intermediate variables for speed optimization
        Real64 c1;
        Real64 c2;
        Real64 xLimit; // Limiting x value to prevent floating point underflow

        CalcPipeTransBeam = 0.0;

        T = 0.0;
        i = 1.0 / N;

        xLimit = (std::log(pow_2(N) * myLocalTiny) / std::log(R)) / xTol;

        c1 = A * std::tan(Theta);
        c2 = 4.0 / Constant::Pi;

        s = i;
        while (s < (1.0 - i)) {
            x = c1 / s;

            if (x < xLimit) {
                dT = c2 * std::pow(R, int(x)) * (1.0 - (1.0 - R) * (x - int(x))) * pow_2(s) / std::sqrt(1.0 - pow_2(s));
                T += dT;
            }

            s += i;
        }

        T /= (N - 1.0); // - 1.0, because started on i, not 0

        CalcPipeTransBeam = T;

        return CalcPipeTransBeam;
    }

Real64 Qv(Real64 const Ta, Real64 const Pa)
    {
        constexpr Real64 Q = 180.;         // W/m^2     , metabolic rate per skin area, steadman1979
        constexpr Real64 phi_salt = 0.9;   //           , vapor saturation pressure level of saline solution, steadman1979
        constexpr Real64 Tc = 310.;        // K         , core temperature, steadman1979
        Real64 Pc = phi_salt * pvstar(Tc); //           , core vapor pressure
        // constexpr Real64 r = 124.;         // Pa/K      , Zf/Rf, steadman1979
        constexpr Real64 eta = 1.43e-6;  // kg/J      , "inhaled mass" / "metabolic rate", steadman1979
        Real64 L = Le(310.);             //           , latent heat of vaporization at 310 K
        constexpr Real64 p = 1.013e5;    // Pa        , atmospheric pressure
        constexpr Real64 rgasa = 287.04; // J/kg/K
        constexpr Real64 rgasv = 461.;   // J/kg/K
        constexpr Real64 cva = 719.;     // J/kg/K
        // constexpr Real64 cvv = 1418.;      // J/kg/K
        constexpr Real64 cpa = cva + rgasa;
        // constexpr Real64 cpv = cvv + rgasv;

        return eta * Q * (cpa * (Tc - Ta) + L * rgasa / (p * rgasv) * (Pc - Pa));
    }

Real64 CalcDetIceStorLMTDstar(Real64 const Tin,  // ice storage unit inlet temperature
                                  Real64 const Tout, // ice storage unit outlet (setpoint) temperature
                                  Real64 const Tfr   // freezing temperature
    )
    {

        // SUBROUTINE INFORMATION:
        //       AUTHOR         Rick Strand
        //       DATE WRITTEN   February 2006
        //       MODIFIED       na
        //       RE-ENGINEERED  na

        // PURPOSE OF THIS SUBROUTINE:
        // This subroutine calculates the log mean temperature difference for
        // the detailed ice storage unit.  The temperature difference is non-
        // dimensionalized using a nominal temperature difference of 10C.
        // This value must be used when obtaining the curve fit coefficients.

        // METHODOLOGY EMPLOYED:
        // Straight-forward calculation where:
        // LMTD* = LMTD/Tnom
        // LMTD = (Tin-Tout)/ln((Tin-Tfr)/(Tout-Tfr))

        Real64 CalcDetIceStorLMTDstar;
        Real64 constexpr Tnom(10.0); // Nominal temperature difference across the ice storage unit [C]

        // First set the temperature differences and avoid problems with the LOG
        // term by setting some reasonable minimums
        Real64 DeltaTio = std::abs(Tin - Tout); // Inlet to outlet temperature difference
        Real64 DeltaTif = std::abs(Tin - Tfr);  // Inlet to freezing temperature difference
        Real64 DeltaTof = std::abs(Tout - Tfr); // Outlet to freezing temperature difference

        if (DeltaTif < DeltaTifMin) {
            DeltaTif = DeltaTifMin;
        }
        if (DeltaTof < DeltaTofMin) {
            DeltaTof = DeltaTofMin;
        }

        CalcDetIceStorLMTDstar = (DeltaTio / std::log(DeltaTif / DeltaTof)) / Tnom;

        return CalcDetIceStorLMTDstar;
    }

