Real64 CSplineint(int const n, // sample data size
                      Real64 x)    // given value of x
    {                              // Cubic Spline interpolation
        // Reference: Numerical Recipes in C (pp.97)
        Real64 A, B, y;
        // find location of x in arrays without searching since array bins are equally sized
        int x_int = static_cast<int>(x);
        //********continuous sample start
        int j = (x_int >> 6) - 1; // sample bin 64, sample size=1651
        if (j < 0) {
            j = 0;
        }
        if (j > (n - 2)) {
            j = n - 2;
        }
        static constexpr Real64 h(64); // sample bin 64, sample size=1651
        //********continuous sample end
        int tsat_fn_pb_x_j1 = 64 * (j + 1); // sample data for pressure
        A = (tsat_fn_pb_x_j1 - x) / h;
        B = 1 - A;
        y = A * tsat_fn_pb_y[j] + B * tsat_fn_pb_y[j + 1] +
            ((A * A * A - A) * (tsat_fn_pb_d2y[j]) + (B * B * B - B) * (tsat_fn_pb_d2y[j + 1])) * (h * h) * 0.1666666667;
        return y;
    }

Real64 PsyCpAirFnW(Real64 const dw // humidity ratio {kgWater/kgDryAir}
    )
    {
        // FUNCTION INFORMATION:
        //       AUTHOR         J. C. VanderZee
        //       DATE WRITTEN   Feb. 1994
        //       MODIFIED       na
        //       RE-ENGINEERED  na

        // PURPOSE OF THIS FUNCTION:
        // This function provides the heat capacity of air {J/kg-C} as function of humidity ratio.

        // METHODOLOGY EMPLOYED:
        // take numerical derivative of PsyHFnTdbW function

        // REFERENCES:
        // see PsyHFnTdbW ref. to ASHRAE Fundamentals
        // USAGE:  cpa = PsyCpAirFnW(w)

        // Static locals
        static Real64 dwSave(-100.0);
        static Real64 cpaSave(-100.0);

        // check if last call had the same input and if it did just use the saved output
        if (dwSave == dw) {
            return cpaSave;
        }

        // compute heat capacity of air
        Real64 const w(max(dw, 1.0e-5));
        Real64 const cpa((1.00484e3 + w * 1.85895e3)); // result => heat capacity of moist air {J/kg-C}

        // save values for next call
        dwSave = dw;
        cpaSave = cpa;

        return cpa;
    }

